module top_module(clk, iA, iB, iC, oResult);input clk;
    input [3:0] iA;
    input [3:0] iB;
    input iC;
    output reg [3:0] oResult; // Changed to reg type

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (iC == 0) begin
            oResult <= iA & iB;
        end else begin
            oResult <= iA | iB;
        end
    end
endmodule
